// test-translation.js
const axios = require('axios');

async function testBackendTranslation() {
  const testCases = [
    { text: "Hello world", lang: "hi" },
    { text: "How are you?", lang: "te" },
    { text: "Thank you", lang: "ta" },
  ];

  for (const test of testCases) {
    try {
      console.log(`Testing: "${test.text}" -> ${test.lang}`);

      const response = await axios.post('http://localhost:3001/api/translate', {
        text: test.text,
        to: test.lang,
        from: 'en'
      }, {
        headers: { 'Content-Type': 'application/json' }
      });

      console.log('Response:', response.data);
      console.log('---');
    } catch (error) {
      console.error(`Error for ${test.lang}:`, error.message);
      if (error.response) {
        console.error('Response data:', error.response.data);
      }
    }
  }
}

testBackendTranslation();
